import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"辉剑圆阵","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/辉剑圆阵.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/辉剑圆阵.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/辉剑圆阵.md"};function _(l,e,i,c,p,b){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"辉剑圆阵",tabindex:"-1"},[n("辉剑圆阵 "),a("a",{class:"header-anchor",href:"#辉剑圆阵","aria-label":'Permalink to "辉剑圆阵"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),o('<h1 id="辉剑圆阵-1" tabindex="-1">辉剑圆阵 <a class="header-anchor" href="#辉剑圆阵-1" aria-label="Permalink to &quot;辉剑圆阵&quot;">​</a></h1><p>辉剑圆阵</p><p>价格：C+1000<br> 描述：<br> 《艾尔登法环》世界中存在的能赋予武器属性，战技的战灰之一。在取得时需要选定自身持有的一个武器，将战灰赋予其上。只有在装备那个武器时，才可以使用战灰的战技。<br> 这个战灰仅可以附着在分类为轻剑，重剑，刺剑的剑类武器以及造成突刺伤害的长柄武器上。<br> 一柄武器仅可以被赋予一个战灰。战灰所选定的武器可以在一次长休时进行变更。<br> 【魔力】：战灰所附带的属性之一，每在智力上具有1点附加成功，就在附加了本战灰的武器的攻击上获得1点器械加值和1点破魔。<br> 【战技：辉剑圆阵】：侍奉卡利亚王室的魔法骑士们使用的战技。让魔力辉剑浮空围成半圆，自动攻击敌人。发动后接着使出重攻击，能向前大幅跨出、突刺攻击。<br> 以一个移动动作，消耗1点意志，你在身旁凝聚出四柄魔力辉剑，最多存在一个场景，但魔力辉剑的存在本身并不会给你带来任何的增益，在已凝聚的魔力辉剑被使用结束之前，你无法通过再使用本战技来获得魔力辉剑。<br> 在一次攻击之前，你可以以一个自由动作让四柄魔力辉剑进行出击，你可以直接在这次攻击中获得4点附加成功，并且对方在应对这次攻击时视为额外受到4点多次攻击减值，这在画风上表现为辉剑圆阵对敌人造成的伤害与干扰。<br> 并且由于辉剑圆阵在命中时造成的冲击力，对手往往会陷入失衡而难以应对你所做出的攻击，因此辉剑出击时，还会使得你这次攻击具有B级别的【先制】效果。<br> 你先行射出辉剑，而后进行攻击，准备更为充分，虽然你大幅跨出进行突刺，但是你仍然不会露出破绽，所以仅在这次攻击中，如果你应用了全力攻击，你在基础防御上受到的减值-2。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',5)])])}const f=r(d,[["render",_]]);export{m as __pageData,f as default};
